}: { value: string; onChange: (v: string) => void; label: string }) => (
  <Field label={label}>
    <div style={{ display: "flex", gap: 6 }}>
      {["Yes", "No"].map(opt => (
        <button
          key={opt}
          type="button"
          onClick={() => onChange(opt)}
          style={{
            flex: 1, padding: "8px 0", border: "1px solid",
            borderRadius: 8, fontSize: 12, fontWeight: 600, cursor: "pointer",
            fontFamily: "inherit", transition: "all .15s",
            borderColor: value === opt ? (opt === "Yes" ? "#16a34a" : "#dc2626") : "#e2e8f0",
            background: value === opt ? (opt === "Yes" ? "#f0fdf4" : "#fef2f2") : "#f8fafc",
            color: value === opt ? (opt === "Yes" ? "#16a34a" : "#dc2626") : "#6b7280",
          }}
        >
          {opt}
        </button>
      ))}
    </div>
  </Field>
);

const EntryCard = ({ onRemove, children }: { onRemove: () => void; children: React.ReactNode }) => (
  <div style={{ border: "1px solid #f1f5f9", borderRadius: 10, padding: "16px", marginBottom: 10, background: "#fafbfc", position: "relative" }}>
    {children}
    <button
      type="button"
      onClick={onRemove}
      style={{
        position: "absolute", top: 12, right: 12, padding: "4px 10px",
        background: "transparent", border: "1px solid #fecaca", borderRadius: 6,
        fontSize: 11, color: "#dc2626", cursor: "pointer", fontFamily: "inherit",
      }}
    >
      Remove
    </button>
  </div>
);

const AddButton = ({ onClick, label }: { onClick: () => void; label: string }) => (
  <button
    type="button"
    onClick={onClick}
    style={{
      display: "inline-flex", alignItems: "center", gap: 6, padding: "8px 16px",
      background: "transparent", border: "1px dashed #cbd5e1", borderRadius: 8,
      fontSize: 12, color: "#64748b", cursor: "pointer", fontFamily: "inherit",
      marginTop: 4, transition: "all .15s",
