export const PDSFormWizard: React.FC<{ employeeId?: number }> = ({ employeeId }) => {
  const [step, setStep] = useState(0);
  const [data, setData] = useState<FormData>(initialData);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const { showToast } = useToastStore();

  useEffect(() => {
    if (employeeId) {
      const loadProfile = async () => {
        setLoading(true);
        try {
          const res = await employeeApi.fetchEmployeeProfile(employeeId);
          if (res.success && res.profile) {
              const p = res.profile as EmployeeDetailed;
              setData(prev => {
                const sp = p.familyBackground?.find(f => f.relationType === 'Spouse');
                const fa = p.familyBackground?.find(f => f.relationType === 'Father');
                const mo = p.familyBackground?.find(f => f.relationType === 'Mother');

                return {
                  ...prev,
                  // Section I: Personal Info
                  firstName: p.firstName || '',
                  lastName: p.lastName || '',
                  middleName: p.middleName || '',
                  suffix: p.suffix || '',
                  birthDate: p.birthDate || '',
                  placeOfBirth: p.placeOfBirth || '',
                  gender: p.gender || '',
                  civilStatus: p.civilStatus || '',
                  heightM: String(p.heightM || ''),
                  weightKg: String(p.weightKg || ''),
                  bloodType: p.bloodType || '',
                  citizenship: p.citizenship || 'Filipino',
                  citizenshipType: p.citizenshipType || '',
                  avatarUrl: p.avatarUrl || '',
                  dualCountry: p.dualCountry || '',

                  // Government IDs
                  gsisNumber: p.gsisNumber || '',
                  pagibigNumber: p.pagibigNumber || '',
                  philhealthNumber: p.philhealthNumber || '',
                  umidNumber: p.umidNumber || '',
                  philsysId: p.philsysId || '',
                  tinNumber: p.tinNumber || '',
                  agencyEmployeeNo: p.agencyEmployeeNo || '',

                  // Address
                  resHouseBlockLot: p.resHouseBlockLot || '',
                  resStreet: p.resStreet || '',
                  resSubdivision: p.resSubdivision || '',
                  resBarangay: p.resBarangay || '',
                  resCity: p.resCity || '',
                  resProvince: p.resProvince || '',
                  resRegion: p.resRegion || '',
                  residentialZipCode: p.residentialZipCode || '',

                  permHouseBlockLot: p.permHouseBlockLot || '',
                  permStreet: p.permStreet || '',
                  permSubdivision: p.permSubdivision || '',
                  permBarangay: p.permBarangay || '',
                  permCity: p.permCity || '',
                  permProvince: p.permProvince || '',
                  permRegion: p.permRegion || '',
                  permanentZipCode: p.permanentZipCode || '',

                  telephoneNo: p.telephoneNo || '',
                  mobileNo: p.mobileNo || '',
                  email: p.email || '',

                  // Section II: Family
                  spouseSurname: sp?.lastName || '',
                  spouseFirstName: sp?.firstName || '',
                  spouseMiddleName: sp?.middleName || '',
                  spouseExtension: sp?.nameExtension || '',
                  spouseOccupation: sp?.occupation || '',
                  spouseEmployer: sp?.employer || '',
                  spouseBusinessAddress: sp?.businessAddress || '',
                  spouseTelephone: sp?.telephoneNo || '',
                  children: p.familyBackground?.filter((f: FamilyMember) => f.relationType === 'Child').map((c: FamilyMember) => ({ 
                    id: String(c.id), 
                    fullName: `${c.lastName || ''}, ${c.firstName || ''} ${c.middleName || ''}`.trim(), 
                    dob: c.dateOfBirth || '' 
                  })) || [],
                  fatherSurname: fa?.lastName || '',
                  fatherFirstName: fa?.firstName || '',
                  fatherMiddleName: fa?.middleName || '',
                  fatherExtension: fa?.nameExtension || '',
                  motherSurname: mo?.lastName || '',
                  motherFirstName: mo?.firstName || '',
                  motherMiddleName: mo?.middleName || '',

                  // Section III: Education (Mapping from relatedData)
                  eduElementarySchool: p.education?.find(e => e.level === 'Elementary')?.institution || '',
                  eduElementaryCourse: p.education?.find(e => e.level === 'Elementary')?.degree || '',
                  eduElementaryFrom: String(p.education?.find(e => e.level === 'Elementary')?.startDate || ''),
                  eduElementaryTo: String(p.education?.find(e => e.level === 'Elementary')?.endDate || ''),
                  eduElementaryUnits: p.education?.find(e => e.level === 'Elementary')?.unitsEarned || '',
                  eduElementaryYearGrad: String(p.education?.find(e => e.level === 'Elementary')?.yearGraduated || ''),
                  eduElementaryHonors: p.education?.find(e => e.level === 'Elementary')?.honors || '',

                  eduSecondarySchool: p.education?.find(e => e.level === 'Secondary')?.institution || '',
                  eduSecondaryCourse: p.education?.find(e => e.level === 'Secondary')?.degree || '',
                  eduSecondaryFrom: String(p.education?.find(e => e.level === 'Secondary')?.startDate || ''),
                  eduSecondaryTo: String(p.education?.find(e => e.level === 'Secondary')?.endDate || ''),
                  eduSecondaryUnits: p.education?.find(e => e.level === 'Secondary')?.unitsEarned || '',
                  eduSecondaryYearGrad: String(p.education?.find(e => e.level === 'Secondary')?.yearGraduated || ''),
                  eduSecondaryHonors: p.education?.find(e => e.level === 'Secondary')?.honors || '',

                  eduVocationalSchool: p.education?.find(e => e.level === 'Vocational')?.institution || '',
                  eduVocationalCourse: p.education?.find(e => e.level === 'Vocational')?.degree || '',
                  eduVocationalFrom: String(p.education?.find(e => e.level === 'Vocational')?.startDate || ''),
                  eduVocationalTo: String(p.education?.find(e => e.level === 'Vocational')?.endDate || ''),
                  eduVocationalUnits: p.education?.find(e => e.level === 'Vocational')?.unitsEarned || '',
                  eduVocationalYearGrad: String(p.education?.find(e => e.level === 'Vocational')?.yearGraduated || ''),
                  eduVocationalHonors: p.education?.find(e => e.level === 'Vocational')?.honors || '',

                  eduCollegeSchool: p.education?.find(e => e.level === 'College')?.institution || '',
                  eduCollegeCourse: p.education?.find(e => e.level === 'College')?.degree || '',
                  eduCollegeFrom: String(p.education?.find(e => e.level === 'College')?.startDate || ''),
                  eduCollegeTo: String(p.education?.find(e => e.level === 'College')?.endDate || ''),
                  eduCollegeUnits: p.education?.find(e => e.level === 'College')?.unitsEarned || '',
                  eduCollegeYearGrad: String(p.education?.find(e => e.level === 'College')?.yearGraduated || ''),
                  eduCollegeHonors: p.education?.find(e => e.level === 'College')?.honors || '',

                  eduGradSchool: p.education?.find(e => e.level === 'Graduate Studies')?.institution || '',
                  eduGradCourse: p.education?.find(e => e.level === 'Graduate Studies')?.degree || '',
                  eduGradFrom: String(p.education?.find(e => e.level === 'Graduate Studies')?.startDate || ''),
                  eduGradTo: String(p.education?.find(e => e.level === 'Graduate Studies')?.endDate || ''),
                  eduGradUnits: p.education?.find(e => e.level === 'Graduate Studies')?.unitsEarned || '',
                  eduGradYearGrad: String(p.education?.find(e => e.level === 'Graduate Studies')?.yearGraduated || ''),
                  eduGradHonors: p.education?.find(e => e.level === 'Graduate Studies')?.honors || '',

                  // Section IV: Eligibility
                  eligibilities: p.eligibilities?.map((e: any) => ({
                    id: String(e.id),
                    name: e.eligibilityType || e.name || '',
                    rating: e.rating || '',
                    examDate: e.examDate || '',
                    examPlace: e.examPlace || '',
                    licenseNo: e.licenseNo || e.licenseNumber || '',
                    licenseValidUntil: e.licenseValidUntil || e.validityDate || ''
                  })) || [],

                  // Section V: Work Experience
                  workExperiences: p.workExperience?.map(w => ({
                    id: String(w.id),
                    positionTitle: w.positionTitle || '',
                    department: w.companyName || '',
                    from: w.dateFrom || '',
                    to: w.dateTo || '',
                    monthlySalary: w.monthlySalary ? String(w.monthlySalary) : '',
                    salaryGrade: w.salaryGrade || '',
                    appointmentStatus: w.appointmentStatus || '',
                    govtService: w.isGovernment ? 'Y' : 'N'
                  })) || [],

                  // Section VI: Voluntary Work
                  voluntaryWorks: p.voluntaryWork?.map(v => ({
                    id: String(v.id),
                    organization: v.organizationName || '',
                    from: v.dateFrom || '',
                    to: v.dateTo || '',
                    hours: String(v.hoursNumber || ''),
                    positionNature: v.position || ''
                  })) || [],

                  // Section VII: Training
                  trainings: p.learningDevelopment?.map(t => ({
                    id: String(t.id),
                    title: t.title || '',
                    from: t.dateFrom || '',
                    to: t.dateTo || '',
                    hours: String(t.hoursNumber || ''),
                    ldType: t.typeOfLd || '',
                    conductedBy: t.conductedBy || ''
                  })) || [],

                  // Section VIII: Other Info (Mapped to flat fields for Wizard state)
                  specialSkills: p.otherInfo?.filter(o => o.type === 'Skill').map(o => o.description).join('\n') || '',
                  nonAcademicDistinctions: p.otherInfo?.filter(o => o.type === 'Recognition').map(o => o.description).join('\n') || '',
                  memberships: p.otherInfo?.filter(o => o.type === 'Membership').map(o => o.description).join('\n') || '',

                  // Section VIII: References
                  references: p.references?.map(r => ({
                    name: r.name || '',
                    address: r.address || '',
                    contact: r.telNo || ''
                  })) || [],

                  // Section IX: Declarations
                  relatedThirdDegree: p.relatedThirdDegree || 'No',
                  relatedThirdDetails: p.relatedThirdDetails || '',
                  relatedFourthDegree: p.relatedFourthDegree || 'No',
                  relatedFourthDetails: p.relatedFourthDetails || '',
                  foundGuiltyAdmin: p.foundGuiltyAdmin || 'No',
                  foundGuiltyDetails: p.foundGuiltyDetails || '',
                  criminallyCharged: p.criminallyCharged || 'No',
                  dateFiled: p.dateFiled || '',
                  statusOfCase: p.statusOfCase || '',
                  convictedCrime: p.convictedCrime || 'No',
                  convictedDetails: p.convictedDetails || '',
                  separatedFromService: p.separatedFromService || 'No',
                  separatedDetails: p.separatedDetails || '',
                  electionCandidate: p.electionCandidate || 'No',
                  electionDetails: p.electionDetails || '',
                  resignedToPromote: p.resignedToPromote || 'No',
                  resignedDetails: p.resignedDetails || '',
                  immigrantStatus: p.immigrantStatus || 'No',
                  immigrantDetails: p.immigrantDetails || '',
                  indigenousMember: p.indigenousMember || 'No',
                  indigenousDetails: p.indigenousDetails || '',
                  personWithDisability: p.personWithDisability || 'No',
                  disabilityIdNo: p.disabilityIdNo || '',
                  soloParent: p.soloParent || 'No',
                  soloParentIdNo: p.soloParentIdNo || '',

                  // Section 42: Govt Issued ID
                  govtIdType: p.govtIdType || '',
                  govtIdNo: p.govtIdNo || '',
                  govtIdIssuance: p.govtIdIssuance || '',
                  ctcNo: p.ctcNo || '',
                  ctcIssuedAt: p.ctcIssuedAt || '',
                  ctcIssuedDate: p.ctcIssuedDate || '',
                  rightThumbmarkUrl: p.rightThumbmarkUrl || '',
                } as FormData;
              });
          }
        } catch (e) {
          showToast("Failed to load profile", "error");
        } finally {
          setLoading(false);
        }
      };
      loadProfile();
    }
  }, [employeeId, showToast]);

  const set = useCallback(<K extends keyof FormData>(key: K, value: FormData[K]) => {
    setData(prev => ({ ...prev, [key]: value }));
  }, []);

  const handleSubmit = async () => {
    if (!data.declarationAgreed) {
      showToast("Please agree to the declaration", "warning");
      return;
    }

    setSubmitting(true);
    try {
      // 1. Prepare payload - ensure we match UpdateEmployeeInput
      const payload: UpdateEmployeeInput = {
        ...data,
        gender: data.gender as Gender, 
        civilStatus: data.civilStatus as CivilStatus,
        heightM: data.heightM ? parseFloat(data.heightM) : null,
        weightKg: data.weightKg ? parseFloat(data.weightKg) : null,
      };

      const res = await employeeApi.updateEmployee(employeeId!, payload);

      if (res.success) {
          showToast("PDS Revised 2025 submitted successfully", "success");
      } else {
          showToast(res.message || "Failed to submit PDS", "error");
      }
    } catch (e) {
      showToast("System error during submission", "error");
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) return <div className="p-12 text-center text-gray-400">Loading PDS Form...</div>;

  return (
    <div style={{ fontFamily: "'Inter', sans-serif", background: "#f1f5f9", width: "100%" }}>
      <div style={{ padding: "16px 24px", width: "100%" }}>

        <div style={{ display: "flex", gap: 6, marginBottom: 20, overflowX: "auto", paddingBottom: 4 }}>
          {STEPS.map(s => (
            <button key={s.id} onClick={() => setStep(s.id)} style={{
                flex: "1 1 0px", minWidth: 0, padding: "10px 4px", borderRadius: 10, border: "1px solid",
                fontSize: 11, fontWeight: 600, cursor: "pointer", textAlign: "center",
                borderColor: step === s.id ? "#bfdbfe" : "#e2e8f0",
                background: step === s.id ? "#eff6ff" : "#fff",
                color: step === s.id ? "#2563eb" : "#64748b",
                transition: "all .15s",
            }}>
              <span style={{ display: "block", fontSize: 13, fontWeight: 700, marginBottom: 2 }}>{s.roman}</span>
              {s.label}
            </button>
          ))}
        </div>

        {step === 0 && <StepPersonal data={data} set={set} />}
        {step === 1 && <StepFamily data={data} set={set} />}
        {step === 2 && <StepEducation data={data} set={set} />}
        {step === 3 && <StepEligibility data={data} set={set} />}
        {step === 4 && <StepWork data={data} set={set} />}
        {step === 5 && <StepVoluntary data={data} set={set} />}
        {step === 6 && <StepTraining data={data} set={set} />}
        {step === 7 && <StepOtherInfo data={data} set={set} />}
        {step === 8 && <StepDeclarations data={data} set={set} />}
      </div>
    </div>
  );
};

export default PDSFormWizard;
